import{_ as a,c as e,o,a1 as r}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"Примечания к выпуску: версионная эволюция | Antigravity-Manager","description":"Узнайте метод версионной эволюции Antigravity-Manager. На странице Settings подтвердите версию и проверьте обновления, через README Changelog просмотрите исправления и напоминания, с помощью /healthz проверьте доступность после обновления.","frontmatter":{"title":"Примечания к выпуску: версионная эволюция | Antigravity-Manager","sidebarTitle":"Понять обновление версии за 3 минуты","subtitle":"Версионная эволюция: основан на встроенном Changelog README","description":"Узнайте метод версионной эволюции Antigravity-Manager. На странице Settings подтвердите версию и проверьте обновления, через README Changelog просмотрите исправления и напоминания, с помощью /healthz проверьте доступность после обновления.","tags":["changelog","release","upgrade","troubleshooting"],"prerequisite":["start-installation","start-proxy-and-first-client"],"order":1},"headers":[],"relativePath":"ru/lbjlaq/Antigravity-Manager/changelog/release-notes/index.md","filePath":"ru/lbjlaq/Antigravity-Manager/changelog/release-notes/index.md"}'),n={name:"ru/lbjlaq/Antigravity-Manager/changelog/release-notes/index.md"};function l(i,t,d,s,g,h){return o(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="версионная-эволюция-основан-на-встроенном-changelog-readme" tabindex="-1">Версионная эволюция: основан на встроенном Changelog README <a class="header-anchor" href="#версионная-эволюция-основан-на-встроенном-changelog-readme" aria-label="Permalink to &quot;Версионная эволюция: основан на встроенном Changelog README&quot;">​</a></h1><p>Вы готовитесь обновить Antigravity Tools, больше всего боитесь не &quot;не обновлено&quot;, а &quot;обновил,才发现 есть изменения совместимости&quot;. Эта страница объясняет метод чтения <strong>Changelog версионной эволюции Antigravity Tools</strong>, чтобы вы могли определить до обновления: что повлияет на вас в этом обновлении.</p><h2 id="чему-вы-научитесь" tabindex="-1">Чему вы научитесь <a class="header-anchor" href="#чему-вы-научитесь" aria-label="Permalink to &quot;Чему вы научитесь&quot;">​</a></h2><ul><li>На странице About быстро подтвердить текущую версию, проверить обновления и получить вход загрузки</li><li>В Changelog README читать только те сегменты версии, которые влияют на вас (а не перелистывать с начала до конца)</li><li>Перед обновлением сделать одну вещь: подтвердить, есть ли &quot;напоминания, требующие изменить конфигурацию/сопоставление моделей вручную&quot;</li><li>После обновления запустить минимальную проверку (<code>/healthz</code>), чтобы подтвердить, что прокси еще можно использовать</li></ul><h2 id="что-такое-changelog" tabindex="-1">Что такое Changelog? <a class="header-anchor" href="#что-такое-changelog" aria-label="Permalink to &quot;Что такое Changelog?&quot;">​</a></h2><p><strong>Changelog</strong> - это список изменений &quot;что изменилось в этот раз&quot; по версиям. Antigravity Tools пишет его напрямую в &quot;Версионная эволюция&quot; README, каждая версия отмечена датой и ключевыми изменениями. Перед обновлением сначала посмотрите Changelog, это уменьшит вероятность столкнуться с проблемами совместимости или регрессией.</p><h2 id="когда-использовать-эту-страницу" tabindex="-1">Когда использовать эту страницу <a class="header-anchor" href="#когда-использовать-эту-страницу" aria-label="Permalink to &quot;Когда использовать эту страницу&quot;">​</a></h2><ul><li>Вы собираетесь обновить со старой версии на новую, хотите сначала подтвердить точки риска</li><li>Вы столкнулись с какой-то проблемой (например, 429/0 Token/Cloudflared), хотите подтвердить, исправлена ли она в последних версиях</li><li>Вы поддерживаете унифицированную версию в команде, нужно дать коллегам метод &quot;читать изменения по версиям&quot;</li></ul><h2 id="🎒-подготовка-перед-началом" tabindex="-1">🎒 Подготовка перед началом <a class="header-anchor" href="#🎒-подготовка-перед-началом" aria-label="Permalink to &quot;🎒 Подготовка перед началом&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Сначала подготовьте путь обновления</p><p>Много способов установки/обновления (brew, ручная загрузка Releases, обновление внутри приложения). Если вы еще не определили, какой путь использовать, сначала смотрите <strong><a href="/docs/opencodedocs/ru/lbjlaq/Antigravity-Manager/start/installation/">Установка и обновление: лучший путь установки для настольной версии (brew / releases)</a></strong>.</p></div><h2 id="делаите-вместе-со-мнои" tabindex="-1">Делайте вместе со мной <a class="header-anchor" href="#делаите-вместе-со-мнои" aria-label="Permalink to &quot;Делайте вместе со мной&quot;">​</a></h2><h3 id="шаг-1-на-странице-about-подтвердите-версию-которую-вы-используете" tabindex="-1">Шаг 1: На странице About подтвердите версию, которую вы используете <a class="header-anchor" href="#шаг-1-на-странице-about-подтвердите-версию-которую-вы-используете" aria-label="Permalink to &quot;Шаг 1: На странице About подтвердите версию, которую вы используете&quot;">​</a></h3><p><strong>Зачем</strong> Changelog организован по версиям. Сначала зная вашу текущую версию, вы знаете &quot;с чего начать чтение&quot;.</p><p>Путь операции: <strong>Settings</strong> → <strong>About</strong>.</p><p><strong>Вы должны увидеть</strong>: В заголовке страницы отображается имя приложения и номер версии (например, <code>v3.3.49</code>).</p><h3 id="шаг-2-нажмите-проверить-обновления-получите-последнюю-версию-и-вход-загрузки" tabindex="-1">Шаг 2: Нажмите &quot;Проверить обновления&quot;, получите последнюю версию и вход загрузки <a class="header-anchor" href="#шаг-2-нажмите-проверить-обновления-получите-последнюю-версию-и-вход-загрузки" aria-label="Permalink to &quot;Шаг 2: Нажмите &quot;Проверить обновления&quot;, получите последнюю версию и вход загрузки&quot;">​</a></h3><p><strong>Зачем</strong> Вам нужно сначала знать &quot;какой номер последней версии&quot;, затем в Changelog выбрать сегменты версий между ними.</p><p>На странице About нажмите &quot;Проверить обновления&quot;.</p><p><strong>Вы должны увидеть</strong>:</p><ul><li>Если есть обновление: появится подсказка &quot;new version available&quot;, и появится кнопка загрузки (открывает <code>download_url</code>)</li><li>Если уже последняя: появится подсказка &quot;latest version&quot;</li></ul><h3 id="шаг-3-в-changelog-readme-читаите-только-те-версии-которые-вы-перескочили" tabindex="-1">Шаг 3: В Changelog README читайте только те версии, которые вы перескочили <a class="header-anchor" href="#шаг-3-в-changelog-readme-читаите-только-те-версии-которые-вы-перескочили" aria-label="Permalink to &quot;Шаг 3: В Changelog README читайте только те версии, которые вы перескочили&quot;">​</a></h3><p><strong>Зачем</strong> Вам нужно заботиться только о изменениях &quot;между вашей текущей версией и последней версией&quot;, другие исторические версии можно сначала пропустить.</p><p>Откройте README, найдите <strong>&quot;Версионная эволюция (Changelog)&quot;</strong>, начинайте с последней версии и читайте вниз, пока не увидите вашу текущую версию.</p><p><strong>Вы должны увидеть</strong>: Версии перечислены в формате <code>vX.Y.Z (YYYY-MM-DD)</code>, и каждая версия имеет групповое описание (например, основные исправления/улучшения функций).</p><h3 id="шаг-4-после-обновления-выполните-минимальную-проверку" tabindex="-1">Шаг 4: После обновления выполните минимальную проверку <a class="header-anchor" href="#шаг-4-после-обновления-выполните-минимальную-проверку" aria-label="Permalink to &quot;Шаг 4: После обновления выполните минимальную проверку&quot;">​</a></h3><p><strong>Зачем</strong> Первая вещь после обновления не &quot;запускать сложные сценарии&quot;, а сначала подтвердить, что прокси может нормально запуститься и может быть проверен клиентом.</p><p>По процессу <strong><a href="/docs/opencodedocs/ru/lbjlaq/Antigravity-Manager/start/proxy-and-first-client/">Запуск локального reverse proxy и подключение первого клиента (/healthz + конфигурация SDK)</a></strong>, минимум один раз проверьте <code>GET /healthz</code>.</p><p><strong>Вы должны увидеть</strong>: <code>/healthz</code> возвращает успех (используется для подтверждения доступности службы).</p><h2 id="сводка-последних-версии-из-readme" tabindex="-1">Сводка последних версий (из README) <a class="header-anchor" href="#сводка-последних-версии-из-readme" aria-label="Permalink to &quot;Сводка последних версий (из README)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Версия</th><th>Дата</th><th>Что вам нужно обратить внимание</th></tr></thead><tbody><tr><td><code>v3.3.49</code></td><td>2026-01-22</td><td>Защита от прерывания Thinking и 0 Token; удален <code>gemini-2.5-flash-lite</code> и напоминание вручную заменить пользовательское сопоставление; настройки языка/темы вступают в силу немедленно; усиление монитора; повышение совместимости OAuth</td></tr><tr><td><code>v3.3.48</code></td><td>2026-01-21</td><td>Фоновый процесс Windows тихо работает (исправлено мерцание консоли)</td></tr><tr><td><code>v3.3.47</code></td><td>2026-01-21</td><td>Усилено сопоставление параметров генерации изображений (<code>size</code>/<code>quality</code>); поддержка туннеля Cloudflared; исправлен сбой запуска, вызванный конфликтами слияния; трехуровневое прогрессивное сжатие контекста</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Как быстро определить &quot;повлияет ли это обновление на меня&quot;</p><p>Приоритетно ищите эти два типа предложений:</p><ul><li><strong>Напоминания пользователям/вам нужно изменить</strong>: например, явно указано, что определенная модель по умолчанию удалена, требуется вручную настроить пользовательское сопоставление</li><li><strong>Основные исправления/исправления совместимости</strong>: например, 0 Token, 429, мерцание Windows, сбой запуска и другие &quot;из-за которых вы не можете использовать&quot; проблемы</li></ul></div><hr><h2 id="приложение-справка-по-исходному-коду" tabindex="-1">Приложение: Справка по исходному коду <a class="header-anchor" href="#приложение-справка-по-исходному-коду" aria-label="Permalink to &quot;Приложение: Справка по исходному коду&quot;">​</a></h2><details><summary><strong>Нажмите, чтобы увидеть местоположение исходного кода</strong></summary><blockquote><p>Обновлено: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Содержимое</th><th>Путь к файлу</th><th>Строки</th></tr></thead><tbody><tr><td>Встроенный Changelog README (версионная эволюция)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/README.md#L324-L455" target="_blank" rel="noreferrer"><code>README.md</code></a></td><td>324-455</td></tr><tr><td>Страница About отображает номер версии и кнопку &quot;Проверить обновления&quot;</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/Settings.tsx#L821-L954" target="_blank" rel="noreferrer"><code>src/pages/Settings.tsx</code></a></td><td>821-954</td></tr><tr><td>Возвращаемая структура команды &quot;Проверить обновления&quot; страницы About</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/Settings.tsx#L187-L215" target="_blank" rel="noreferrer"><code>src/pages/Settings.tsx</code></a></td><td>187-215</td></tr><tr><td>Уведомление об автоматическом обновлении (загрузка и перезапуск)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/UpdateNotification.tsx#L33-L96" target="_blank" rel="noreferrer"><code>src/components/UpdateNotification.tsx</code></a></td><td>33-96</td></tr><tr><td>Текущий номер версии (метаданные сборки)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/package.json#L1-L4" target="_blank" rel="noreferrer"><code>package.json</code></a></td><td>1-4</td></tr></tbody></table></details>',34)])])}const b=a(n,[["render",l]]);export{u as __pageData,b as default};
